INSERT INTO engine_bug_queue (bug_class, title, severity, owner_cluster, root_cause, prevention_rule, probe_type, probe_logic, status, concepts_affected, fixed_in_files, discovered_in_session, row_type) VALUES
('gss_constant_field_arrow_must_not_shrink_with_distance', 'Cap E-arrow length must be CONSTANT in d for an infinite sheet — blind-cloning the line''s 1/r arrow makes it shrink as the field point moves away (wrong physics shown faithfully)', 'CRITICAL', 'peter_parker:renderer_primitives', 'gauss_law_line''s ring-arrow length is glnArrowLen(λ, r) = 1/r. The sheet''s field is E = σ/(2ε₀) — CONSTANT, independent of distance — so cloning the line''s arrow-length law would make the cap arrows shrink as d grows, contradicting the whole lesson (the field that never dies). Rule 29: a length tracks the REAL magnitude, which here depends only on |σ|.', 'For the sheet, the cap-arrow length is gssArrowLen(σ) = demo·|σ| with NO distance term; it must be byte-identical at every d. The coordinated d-sweep + STATE_7 d-slider MOVE the field-point/pillbox geometry while the cap-arrow length HOLDS. Never reuse the line''s 1/r (or the sphere''s 1/r²) arrow law for a planar/constant-field sibling.', 'manual', 'Open STATE_6 (coordinated sweep) or STATE_7 and slide d from near to far; the cap arrows must keep IDENTICAL length while their anchor (the pillbox cap / field point P) slides away. Only σ changes the arrow length.', 'FIXED', ARRAY['gauss_law_sheet'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-26_gauss_sheet_build', 'incident'),
('gss_flux_roles_inverted_caps_pierce_wall_grazes', 'Pillbox flux roles are the INVERSE of the line: the two CAPS carry all the flux (pierced ⊥), the curved WALL is zero-flux (grazed ∥) + "Φ=0" — cloning the line puts the flux on the wrong face', 'CRITICAL', 'peter_parker:renderer_primitives', 'In gauss_law_line the WALL pierces (the flux-bearing ring) and the CAPS graze (Φ=0). For the planar pillbox the geometry inverts: the caps are parallel to the sheet and pierced ⊥ by E (flux-bearing, constant-length arrows both sides), and the curved wall is perpendicular to the sheet and grazed ∥ by E (zero flux). A blind clone would draw the flux-bearing arrows on the wall and the Φ=0 tag on the caps — exactly wrong.', 'gss draws CONSTANT-length pierce arrows along ±X on each cap (gss_cap_arrow, show_cap_arrows) and BRIGHT-yellow grazing arrows along ±X lying ON the curved wall (gss_wall_graze_arrow) + the single "Φ=0" wall tag (show_caps_flux). The pierce-vs-graze contrast is the SUPPORTING aha and the explicit inverse of the line — verify it reads as caps-pierce / wall-graze, never the reverse.', 'manual', 'Open STATE_4 (wall-zero-flux beat); the two flat caps must show green arrows piercing straight out ⊥ (away from the sheet on both sides), and the curved wall must show yellow arrows lying along the wall surface (axial, grazing) with the "Φ=0" tag — the inverse of the line.', 'FIXED', ARRAY['gauss_law_sheet'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-26_gauss_sheet_build', 'incident'),
('gss_plot_is_flat_line_above_falling_ghosts_not_a_falling_curve', 'E-vs-distance plot must be a FLAT horizontal sheet line above FALLING 1/r & 1/r² ghosts — inheriting the line''s falling 1/r curve is the load-bearing cut-line inversion bug', 'CRITICAL', 'peter_parker:renderer_primitives', 'gauss_law_line''s plot draws a falling green 1/r curve with a faint 1/r² ghost. The sheet inverts the cut-line (scar teach_inverted_scenario_inverts_cutline_flags): the sheet field is CONSTANT, so the green curve must be a FLAT horizontal line, with the 1/r (line) and 1/r² (point) curves drawn as FAINT FALLING GHOSTS beneath it. Blind-cloning the line''s plot draws a falling sheet curve — the single most load-bearing inversion to get wrong.', 'gss_plot draws a flat green line at σ/2ε₀ (constant, independent of d) ABOVE two faint dashed falling ghosts (1/r orange line-ghost, 1/r² grey point-ghost) normalised to coincide at d0; the tracking dot rides the flat line — slides RIGHT, holds the SAME height. Surface show_constant_field framing. Never reuse the falling-curve plot from a 1/r or 1/r² sibling.', 'manual', 'Open STATE_6 and watch the sweep; the green sheet line must stay FLAT (horizontal) while the dashed ghosts fall, and the glowing dot must slide horizontally along the flat line at constant height — never trace a descending curve.', 'FIXED', ARRAY['gauss_law_sheet'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-26_gauss_sheet_build', 'incident'),
('gss_two_distinct_reference_lines_d_billboarded_H_axial', 'd (perpendicular distance, billboarded) and H (pillbox half-height, axial) must read as two DISTINCT labelled lines — both lie along the sheet normal and conflate if drawn alike', 'MAJOR', 'peter_parker:renderer_primitives', 'Unlike the line (where r was radial and L was axial — naturally perpendicular), the sheet''s d (sheet→field-point) and H (pillbox half-height) BOTH lie along the sheet normal (±X), so they conflate if drawn the same way. The area A is on the cap and must never read as a distance.', 'gss draws d as a camera-right-billboarded distance ruler from the sheet to P (gss_dist_vector, kind "d", with the P tip), and H as a genuinely axial +X ruler offset to the +Y side of the pillbox (gss_half_vector, kind "H"); A is a cap-face label (gss_cap_area_label), never a line. The H line is gated on the pillbox beat (show_pillbox / emerge_H_at_ms / sliders), never on show_reference_lines alone, so STATE_2 teaches d before the pillbox exists.', 'manual', 'Open STATE_3+; d must be a clearly horizontal ruler ending in the P dot at the field point, H a separate axial ruler beside the pillbox, and A a label on the cap face — three distinct readings, never one merged line.', 'FIXED', ARRAY['gauss_law_sheet'], ARRAY['src/lib/renderers/field_3d_renderer.ts'], 'session_2026-06-26_gauss_sheet_build', 'incident'),
('gss_devstatemeta_block_registered_same_change', 'gauss_law_sheet per-state keys registered in deriveStateMeta in the SAME change (else THE EYE mis-classifies every state at the 1500ms default)', 'MAJOR', 'peter_parker:renderer_primitives', 'A new field_3d scenario whose per-state gauss_sheet keys (cap_arrow_at_ms, caps_reveal_at_ms, derivation_at_ms, emerge_d/H_at_ms, area_label_at_ms, sweep_end_at_ms, plot_draw_at_ms, gaussian_fade_at_ms, sliders) are not recognised by maxRevealForField3dState/deriveHoldExpectations classifies at the 1500ms default and false-fails D7/D1p (the field3d_scenario_missing_devstatemeta_recognition scar).', 'The gauss_sheet reveal block (maxRevealForField3dState) + the sliders→interactive hold classification (deriveHoldExpectations) ship in the SAME change as the renderer scenario. Guided STATE_2–6 must classify reveal_hold (maxReveal > 1500ms); the STATE_7 slider state must classify interactive.', 'manual', 'Run visual:eyes on a gauss_law_sheet concept; guided states must classify reveal_hold and the explore state interactive in the Reveal/Hold map — none at the bare 1500ms default.', 'FIXED', ARRAY['gauss_law_sheet'], ARRAY['src/lib/validators/visual/deriveStateMeta.ts'], 'session_2026-06-26_gauss_sheet_build', 'incident')
